module RefModule(
    input CLK,
    input LOAD,
    input [3:0] DATA,
    output reg [3:0] Q
);reg [3:0] reg_out;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (LOAD) begin
        reg_out <= DATA;
    end else begin
        reg_out <= {reg_out[2:0], 1'b0};
    end
end

assign Q = reg_out;

endmodule
